275	    pub(crate) fn remote_key_to_expr<'a>(&'a self, key_expr: &'a WireExpr) -> ZResult<KeyExpr<'a>> {
276	        if key_expr.scope == EMPTY_EXPR_ID {
277	            Ok(unsafe { keyexpr::from_str_unchecked(key_expr.suffix.as_ref()) }.into())
278	        } else if key_expr.suffix.is_empty() {
279	            match self.get_remote_res(&key_expr.scope, key_expr.mapping) {
280	                Some(Resource::Node(ResourceNode { key_expr, .. })) => Ok(key_expr.into()),
281	                Some(Resource::Prefix { prefix }) => bail!(
282	                    "Received {:?}, where {} is `{}`, which isn't a valid key expression",
283	                    key_expr,
284	                    key_expr.scope,
285	                    prefix
286	                ),
287	                None => bail!("Remote resource {} not found", key_expr.scope),
288	            }
289	        } else {
290	            [
291	                match self.get_remote_res(&key_expr.scope, key_expr.mapping) {
292	                    Some(Resource::Node(ResourceNode { key_expr, .. })) => key_expr.as_str(),
293	                    Some(Resource::Prefix { prefix }) => prefix.as_ref(),
294	                    None => bail!("Remote resource {} not found", key_expr.scope),
295	                },
296	                key_expr.suffix.as_ref(),
297	            ]
298	            .concat()
299	            .try_into()
300	        }
301	    }
