303	    pub(crate) fn local_wireexpr_to_expr<'a>(
304	        &'a self,
305	        key_expr: &'a WireExpr,
306	    ) -> ZResult<KeyExpr<'a>> {
307	        if key_expr.scope == EMPTY_EXPR_ID {
308	            key_expr.suffix.as_ref().try_into()
309	        } else if key_expr.suffix.is_empty() {
310	            match self.get_local_res(&key_expr.scope) {
311	                Some(Resource::Node(ResourceNode { key_expr, .. })) => Ok(key_expr.into()),
312	                Some(Resource::Prefix { prefix }) => bail!(
313	                    "Received {:?}, where {} is `{}`, which isn't a valid key expression",
314	                    key_expr,
315	                    key_expr.scope,
316	                    prefix
317	                ),
318	                None => bail!("Remote resource {} not found", key_expr.scope),
319	            }
320	        } else {
321	            [
322	                match self.get_local_res(&key_expr.scope) {
323	                    Some(Resource::Node(ResourceNode { key_expr, .. })) => key_expr.as_str(),
324	                    Some(Resource::Prefix { prefix }) => prefix.as_ref(),
325	                    None => bail!("Remote resource {} not found", key_expr.scope),
326	                },
327	                key_expr.suffix.as_ref(),
328	            ]
329	            .concat()
330	            .try_into()
331	        }
332	    }
