540	#[derive(Default)]
541	struct SubscriberCallbacks(SingleOrVec<(Callback<Sample>, KeyExpr<'static>)>);
542	
543	impl SubscriberCallbacks {
544	    fn is_empty(&self) -> bool {
545	        self.0.is_empty()
546	    }
547	
548	    #[inline(always)]
549	    fn call(
550	        self,
551	        consume: bool,
552	        qos: push::ext::QoSType,
553	        msg: &mut PushBody,
554	        #[cfg(feature = "unstable")] reliability: Reliability,
555	    ) {
556	        let zenoh_collections::single_or_vec::IntoIter { drain, last } = self.0.into_iter();
557	        for (cb, key_expr) in drain {
558	            #[cfg(feature = "unstable")]
559	            cb.call_with_message((key_expr, qos, &mut msg.clone(), reliability));
560	            #[cfg(not(feature = "unstable"))]
561	            cb.call_with_message((key_expr, qos, &mut msg.clone()));
562	        }
563	        if let Some((cb, key_expr)) = last {
564	            let mut msg = &mut *msg;
565	            let mut msg_clone;
566	            if !consume {
567	                msg_clone = msg.clone();
568	                msg = &mut msg_clone;
569	            }
570	            #[cfg(feature = "unstable")]
571	            cb.call_with_message((key_expr, qos, msg, reliability));
572	            #[cfg(not(feature = "unstable"))]
573	            cb.call_with_message((key_expr, qos, msg));
574	        }
575	    }
576	}
