616	impl Resource {
617	    pub(crate) fn new(name: Box<str>) -> Self {
618	        if keyexpr::new(name.as_ref()).is_ok() {
619	            Self::for_keyexpr(unsafe { OwnedKeyExpr::from_boxed_str_unchecked(name) })
