            plugins_manager: None,
            #[cfg(feature = "shared-memory")]
            shm_clients: None,
            #[cfg(test)]
            subregions: None,
            #[cfg(test)]
            disable_async_tree_computation: false,
        }
    }

    #[cfg(all(feature = "plugins", feature = "internal"))]
